-- ------------------------------------------------------------------------------------------------------------ --
-- 명칭 : currency
-- 작성 : 2026.07.13 trisakion
-- 내용 : 유저별 재화 잔액 (유저당 재화종류마다 1행)
-- ------------------------------------------------------------------------------------------------------------ --
SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS `currency`;
CREATE TABLE `currency` (
  `currency_id`				BIGINT		UNSIGNED	NOT NULL	AUTO_INCREMENT												COMMENT '재화 ID',
  `user_id`					BIGINT		UNSIGNED	NOT NULL														COMMENT '유저 ID',
  `currency_type`			TINYINT		UNSIGNED	NOT NULL														COMMENT '재화 종류 (1:유료다이아, 2:무료다이아, 3:골드)',
  `amount`					BIGINT					NOT NULL	DEFAULT 0											COMMENT '보유 수량',
  `updated_at`				DATETIME				NOT NULL	DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP	COMMENT '수정일시',
  PRIMARY KEY (`currency_id`),
  UNIQUE KEY `uk_currency_user_type` (`user_id`, `currency_type`),
  CONSTRAINT `fk_currency_user_id` FOREIGN KEY (`user_id`) REFERENCES `user` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='유저별 재화 잔액';
SET FOREIGN_KEY_CHECKS = 1;
